+        (ClaimDomain::Compatibility, "compatibility"),
+        (ClaimDomain::ShippedSurface, "shipped_surface"),
+        (ClaimDomain::React, "react"),
+        (ClaimDomain::Supremacy, "supremacy"),
+        (ClaimDomain::Rollout, "rollout"),
+        (ClaimDomain::Ga, "ga"),
